#!/bin/bash ############################################## # Author: netkiller<netkiller@msn.com> # Homepage: http://www.netkiller.cn # Date: 2017-02-08 # $Author$ # $Id$ ############################################## # chkconfig: 345 100 02 # description: Spring boot application # processname: springbootd # File : springbootd ############################################## BASEDIR="/www/netkiller.cn/api.netkiller.cn" JAVA_HOME=/srv/java JAVA_OPTS="-server -Xms2048m -Xmx8192m -Dlog.level.console=warn -Djava.security.egd=file:/dev/./urandom" PACKAGE="api.netkiller.cn-0.0.2-release.jar" CONFIG="--spring.config.location=$BASEDIR/application.properties" USER=www ############################################## NAME=springbootd PROG="$JAVA_HOME/bin/java $JAVA_OPTS -jar $BASEDIR/$PACKAGE $CONFIG" LOGFILE=/var/tmp/$NAME.log PIDFILE=/var/tmp/$NAME.pid ACCESS_LOG=/var/tmp/$NAME.access.log ##############################################
function log(){ echo "$(date -d "today" +"%Y-%m-%d %H:%M:%S") $1 $2" >> $LOGFILE }
function start(){ if [ -f "$PIDFILE" ]; then echo $PIDFILE exit 2 fi
su - $USER -c "$PROG & echo \$! > $PIDFILE" log info start } function stop(){ [ -f $PIDFILE ] && kill `cat $PIDFILE` && rm -rf $PIDFILE log info stop } function status(){ ps aux | grep $PACKAGE | grep -v grep | grep -v status log info status } function reset(){ pkill -f $PACKAGE [ -f $PIDFILE ] && rm -rf $PIDFILE log info reset }
case "$1" in start) start ;; stop) stop ;; status) status ;; restart) stop start ;; log) tail -f $LOGFILE ;; reset) reset ;; *) echo $"Usage: $0 {start|stop|status|restart|log|reset}" esac exit $?


user www;
worker_processes 1;

error_log /var/log/nginx/error.log warn;
pid /var/run/nginx.pid;


server {
	listen 443 ssl http2;

	ssl_certificate server.crt;
	ssl_certificate_key server.key;
}


			#让http请求重定向到https请求

server {
	listen 80;
	error_page 497 https://$host$uri?$args;
	rewrite ^(.*)$ https://$host$1 permanent;
}


server {
	listen 80
	listen 443 ssl http2;

	ssl_certificate server.crt;
	ssl_certificate_key server.key;

	error_page 497 https://$host$uri?$args;

	if ($scheme = http) {
		return 301 https://$server_name$request_uri;
	}
}


upstream backend {
	server server1.example.com:8080;
	server server2.example.com:8080 backup;
}
server {
	location / {
		proxy_pass http://backend;
	}
}


upstream frontend {
	server server1.example.com:8080 backup;
	server server2.example.com:8080;
}
server {
	location / {
		proxy_pass http://frontend;
	}
}


server {
    listen       80;
    server_name  localhost;

    location /status {
        stub_status on;
        access_log off;
        allow 127.0.0.1;
        deny all;
    }
}


pipeline {
    agent {
        label "java-8"
    }
    stages  {
        stage("初始化") {
        	steps{
        	    sh 'apt install -y sshpass'
                sh 'sshpass -v'
        	}
        }
        stage("检出") {
            steps {
                checkout(
                  [$class: 'GitSCM', branches: [[name: env.GIT_BUILD_REF]], 
                  userRemoteConfigs: [[url: env.GIT_REPO_URL]]]
                )
            }
        }

        stage("编译") {
            steps {
                sh "mvn package -Dmaven.test.skip=true"
            }
        }

        stage("测试") {
            steps {
              	sh "mvn test"
            }
        }

        stage("保存构建产物") {
            steps {
                archiveArtifacts artifacts: 'target/*.jar', fingerprint: true
              	sh "ls -l target/*.jar"
            }
        }
        stage("部署"){
            parallel{
            	stage('stop') {
			         steps {
			            sh 'sshpass -p 123456 ssh -f www@www.netkiller.cn pkill -f java-project-0.0.2-SNAPSHOT'
			         }
			    }
			    stage('start') {
			         steps {
			            sh 'sshpass -p 123456 scp target/*.jar www@www.netkiller.cn:/opt/'
                	    sh 'sshpass -p 123456 ssh -f www@www.netkiller.cn java -jar /opt/java-project-0.0.2-SNAPSHOT.jar'
			          }
			    }	                
    	    }
    	}
    }
}


